    ["Click Teleporter"] = "Cliquez sur le téléporteur",
    ["Click the ^Downward Draft^ to be flown to the platform and engage ^Dathea, Ascended^."] = "Cliquez sur ^Downward Draft^ pour être transporté jusqu'à la plateforme et affronter ^Dathea, Ascended^.",
    ["Click the ^Hammer of Khaz'goroth^ in the middle of this room after killing ^Demonic Inquisition^."] = "Cliquez sur ^Hammer of Khaz'goroth^ au centre de cette salle après avoir tué ^Demonic Inquisition^.",
    ["Click the ^Tears of Elune^ in the middle of the room after killing ^The Desolate Host^."] = "Cliquez sur ^Tears of Elune^ au centre de la salle après avoir tué ^The Desolate Host^.",
    ["Click the ^Tidestone of Golganneth^ after killing ^Mistress Sassz'ine^."] = "Cliquez sur ^Tidestone of Golganneth^ après avoir tué ^Mistress Sassz'ine^.",
    ["Click the portal to ^Wellspring Atrium^ to be teleported to the entrance."] = "Cliquez sur le portail vers ^Wellspring Atrium^ pour être téléporté à l'entrée.",
    ["Click Tidestone"] = "Cliquez sur la Pierre-des-Marées",
    ["Click Titan Console"] = "Cliquez sur la console des Titans",
