    ["Click Valeera"] = "Cliquez sur Valeera",
    ["Continue ahead into the main courtyard to find ^Spellblade Aluriel^."] = "Continuez jusqu'à la cour principale pour trouver ^Spellblade Aluriel^.",
    ["Continue ahead to clear the trash and engage ^King Rastakhan^."] = "Continuez, éliminez les ennemis et affrontez ^King Rastakhan^.",
    ["Continue backtracking through this room."] = "Continuez à revenir sur vos pas dans cette salle.",
    ["Continue down spiral"] = "Descendez la spirale",
    ["Continue down the path and clear the trash to spawn ^The Amalgamation Chamber^."] = "Descendez le chemin et éliminez les ennemis pour faire apparaître ^The Amalgamation Chamber^.",
    ["Continue down the stairs, following the path until you reach ^Sisters of the Moon^."] = "Descendez l'escalier en suivant le chemin jusqu'à ^Sisters of the Moon^.",
    ["Continue following the linear path into the next room."] = "Continuez sur le chemin linéaire jusqu'à la salle suivante.",
    ["Continue following the path ahead to reach ^Sennarth^."] = "Continuez sur le chemin devant vous jusqu'à ^Sennarth^.",
    ["Continue following the path ahead to reach ^Terros^."] = "Continuez sur le chemin devant vous jusqu'à ^Terros^.",
    ["Continue following the path to arrive back at the ^The Primal Bulwark^."] = "Continuez sur le chemin pour retourner à ^The Primal Bulwark^.",
    ["Continue following the path to engage ^Fetid Devourer^."] = "Continuez sur le chemin pour affronter ^Fetid Devourer^.",
    ["Continue following the path to reach ^Vectis^."] = "Continuez sur le chemin jusqu'à ^Vectis^.",
    ["Continue following the path to reach ^Zek'voz, Herald of N'Zoth^. Clear trash to start the encounter."] = "Continuez sur le chemin jusqu'à ^Zek'voz, Herald of N'Zoth^. Éliminez les ennemis pour commencer le combat.",
    ["Continue forward to ^The Jailer^'s platform and end this."] = "Continuez jusqu'à la plateforme de ^The Jailer^ et mettez-y un terme.",
    ["Continue straight ahead to engage ^Conclave of the Chosen^."] = "Continuez tout droit pour affronter ^Conclave of the Chosen^.",
    ["Continue to Blackhand"] = "Continuez vers Main-Noire",
    ["Continue up and around the stairwell until you reach ^Tichondrius^."] = "Continuez à monter et contourner l'escalier jusqu'à ^Tichondrius^.",
    ["Continue working your way towards the central hub. When you get there, take the first path on the left and take the portal to ^Grizzly Hills^."] = "Continuez vers le carrefour central. Une fois sur place, prenez le premier chemin à gauche, puis le portail vers ^Grizzly Hills^.",
    ["Cross Bridge Ahead"] = "Traversez le pont",
    ["Cross Lava to Neltharion's Sanctum"] = "Traversez la lave vers le sanctum",
    ["Cross the bridge behind ^Anduin^ to the teleporter. Select ^Proceed^."] = "Traversez le pont derrière ^Anduin^ jusqu'au téléporteur. Sélectionnez ^Proceed^.",
    ["Cross the room and take the southern exit."] = "Traversez la salle et prenez la sortie sud.",
    ["Cross to Maiden"] = "Traversez vers la Damoiselle",
    ["Destroy Bells"] = "Détruisez les cloches",
    ["Destroy Cannons"] = "Détruisez les canons",
    ["Dialog then Anduin"] = "Dialogue, puis Anduin",
    ["Dialog then Portal"] = "Dialogue, puis portail",
