    ["Dialog then Sludgefist"] = "Dialogue, puis Fangepoing",
    ["Dialog then Sylvanas"] = "Dialogue, puis Sylvanas",
    ["Dialog then Titan Console"] = "Dialogue, puis console des Titans",
    ["Displacement Pad"] = "Plateforme de déplacement",
    ["Door"] = "Porte",
    ["Down spiral to Shad'har"] = "Descendez la spirale vers Shad'har",
    ["Down stairwell"] = "Descendez la cage d'escalier",
    ["Down to Cenarius"] = "Descendez vers Cénarius",
    ["Down to Cho"] = "Descendez vers Cho",
    ["Down to Sisters"] = "Descendez vers les Sœurs",
    ["Downstairs across to Magmaw"] = "En bas, traversez vers Magmaw",
    ["Dragons"] = "Dragons",
    ["Dragons then Khadgar"] = "Dragons, puis Khadgar",
    ["Draven Starts Sludgefist"] = "Draven lance Fangepoing",
    ["During dance phase, run to the spotlight. Walk in the direction of the other NPCs a few times. Jump to clear debuff stacks."] = "Pendant la phase de danse, courez sous le projecteur. Marchez plusieurs fois dans la même direction que les autres PNJ. Sautez pour dissiper les cumuls d'affaiblissement.",
    ["East Exit"] = "Sortie est",
    ["East then Elevator"] = "Est, puis ascenseur",
    ["East then South"] = "Est, puis sud",
    ["East to Elevator"] = "Est vers l'ascenseur",
    ["East to Xhul'horac"] = "Est vers Xhul'horac",
    ["Ebon Blade Acolyte"] = "Acolyte de la Lame d'ébène",
    ["Eiendormi on Right"] = "Eiendormi à droite",
    ["Elevator"] = "Ascenseur",
    ["Elevator to Blackhand"] = "Ascenseur vers Main-Noire",
    ["Elevator to Terrace"] = "Ascenseur vers la terrasse",
